class Solution:
    def smallestBeautifulString(self, s, k):
        def is_beautiful(t):
            for i in range(len(t)):
                if i >= 1 and t[i] == t[i - 1]:
                    return False
                if i >= 2 and t[i] == t[i - 2]:
                    return False
            return True

        n = len(s)

        def to_int(a):
            v = 0
            for ch in a:
                v = v * k + (ord(ch) - ord('a'))
            return v

        def to_str(v, n):
            digits = []
            for _ in range(n):
                digits.append(chr(ord('a') + v % k))
                v //= k
            return ''.join(reversed(digits))

        cur = to_int(list(s)) + 1
        limit = k ** n
        while cur < limit:
            cand = to_str(cur, n)
            if is_beautiful(cand):
                return cand
            cur += 1
        return ''

