class Solution:
    def smallestBeautifulString(self, s: str, k: int) -> str:
        arr = list(s)
        n = len(arr)
        i = n - 1
        while i >= 0:
            c = ord(arr[i]) - ord('a') + 1
            found = False
            while c < k:
                ch = chr(ord('a') + c)
                if (i >= 1 and arr[i - 1] == ch) or (i >= 2 and arr[i - 2] == ch):
                    c += 1
                    continue
                arr[i] = ch
                found = True
                break
            if found:
                for j in range(i + 1, n):
                    for c2 in range(k):
                        ch2 = chr(ord('a') + c2)
                        if (j >= 1 and arr[j - 1] == ch2) or (j >= 2 and arr[j - 2] == ch2):
                            continue
                        arr[j] = ch2
                        break
                return ''.join(arr)
            i -= 1
        return ''

