var smallestBeautifulString = function(s, k) {
    const arr = s.split('');
    const n = arr.length;
    let i = n - 1;
    while (i >= 0) {
        let c = arr[i].charCodeAt(0) - 97 + 1;
        let found = false;
        while (c < k) {
            const ch = String.fromCharCode(97 + c);
            if ((i >= 1 && arr[i - 1] === ch) || (i >= 2 && arr[i - 2] === ch)) {
                c++;
                continue;
            }
            arr[i] = ch;
            found = true;
            break;
        }
        if (found) {
            for (let j = i + 1; j < n; j++) {
                for (let c2 = 0; c2 < k; c2++) {
                    const ch2 = String.fromCharCode(97 + c2);
                    if ((j >= 1 && arr[j - 1] === ch2) || (j >= 2 && arr[j - 2] === ch2)) {
                        continue;
                    }
                    arr[j] = ch2;
                    break;
                }
            }
            return arr.join('');
        }
        i--;
    }
    return '';
};
